import Header from './Header';
import Content from './Content';
import Footer from './Footer';
import Additems from './Additems';
import { useState } from 'react';
import ListItems from './ListItems';
import SearchItem from './SearchItem';

function App() {
  const storedItems = JSON.parse(localStorage.getItem('ToDoList-ListAll')) || [];
  const [items, setItems] = useState(storedItems);

  const handleChange = (id) => {
    const updatedItems = items.map(item => (item.id === id) ? { ...item, checked: !item.checked } : item);
    setItems(updatedItems);
    localStorage.setItem("ToDoList-ListAll", JSON.stringify(updatedItems));
  }

  const changeDelete = (id) => {
    const updatedItems = items.filter(item => item.id !== id);
    setItems(updatedItems);
    localStorage.setItem("ToDoList-ListAll", JSON.stringify(updatedItems));
  }

  const addItem = (activity) => {
    const id = items.length ? items[items.length - 1].id + 1 : 1;
    const newItems = [...items, { id, activity, checked: false }];
    setItems(newItems);
    localStorage.setItem("ToDoList-ListAll", JSON.stringify(newItems));
  }

  const [newItem, setNewItem] = useState('');

  const handleSubmit = (e) => {
    e.preventDefault();
    if (!newItem) return;
    addItem(newItem);
    setNewItem('');
  }

  const [search, setSearch] = useState('');

  return (
    <div>
      <Header title="To-Do Lists"/>
      <SearchItem search={search} setSearch={setSearch}/>
      <Additems newItem={newItem} setNewItem={setNewItem} handleSubmit={handleSubmit}/>
      <Content items={items.filter(item => item.activity.toLowerCase().includes(search.toLowerCase()))} changeDelete={changeDelete} handleChange={handleChange}/>
      <Footer items={items}/> {/* Ensure that `items` passed here is an array */}
    </div>
  );
}

export default App;
